function renderReview() {
  const all = getReviewItems();
  const query = normalize($("reviewSearch").value);
  const kind = $("reviewKindFilter").value;
  const range = $("reviewRangeFilter").value;
  const reason = $("reviewReasonFilter").value;

  const filtered = all.filter((item) => {
    const haystack = normalize([item.id, item.title, item.subtitle, item.status, item.reason].join(" "));
    const rangeOk = range === "all" || (range === "week" ? item.days <= 7 : item.days <= 0);
    return (!query || haystack.includes(query))
      && (!kind || item.kind === kind)
      && rangeOk
      && (!reason || item.reasonType === reason);
  });

  const dueNow = all.filter((item) => item.days <= 0).length;
  const dueWeek = all.filter((item) => item.days > 0 && item.days <= 7).length;
  $("reviewSummary").textContent = `К повторению сейчас: ${dueNow}. На ближайшие 7 дней: ${dueWeek}. Показано: ${filtered.length}.`;

  if (!filtered.length) {
    $("reviewList").innerHTML = `
      <div class="empty-state">
        <strong>Нет задач для выбранного фильтра</strong>
        <span>Попробуй выбрать «Все запланированные» или отметь темы/задачи статусом «Повторить».</span>
      </div>
    `;
    return;
  }

  $("reviewList").innerHTML = filtered.map((item) => `
    <article class="review-card ${item.bucket}">
      <div>
        <div class="topic-badges-line">
          <span class="badge">${item.kind === "topic" ? "Тема" : "Задача"}</span>
          <span class="badge">${escapeHTML(item.id)}</span>
          <span class="badge ${statusClass(item.status)}">${escapeHTML(item.status)}</span>
          <span class="badge due-${item.bucket}">${escapeHTML(dueLabel(item.days))}</span>
        </div>
        <h3>${escapeHTML(item.title)}</h3>
        <div class="meta">
          <span>${escapeHTML(item.subtitle)}</span>
        </div>
        <div class="review-date">
          <span class="badge">Дата повторения: ${escapeHTML(item.due)}</span>
          <span class="badge">Интервал: ${escapeHTML(item.interval)} дн.</span>
          ${item.score !== "" ? `<span class="badge">Самооценка: ${escapeHTML(item.score)}/5</span>` : ""}
        </div>
        <p class="review-reason">${escapeHTML(item.reason)}</p>
      </div>
      <div class="review-actions">
        <button class="btn js-review-done" data-kind="${escapeHTML(item.kind)}" data-id="${escapeHTML(item.id)}">Повторила сегодня</button>
        ${item.kind === "topic" ? `<button class="btn ghost js-review-open-topic" data-query="${escapeHTML(item.id)}">Открыть тему</button>` : `<a class="btn ghost" href="${escapeHTML(item.raw.url || "#")}" target="_blank" rel="noreferrer">Открыть LeetCode</a>`}
      </div>
    </article>
  `).join("");

  bindReviewEvents();
}

function renderPlan() {
  const topics = getTopics();
  const practice = getPractice();
  const doneTopics = topics.filter((item) => item.status === "Готово").length;
  const donePractice = practice.filter((item) => item.status === "Решено").length;
  const deadline = calculateDeadlineState();
  const remainingWeeks = Math.max(1, deadline.remainingWeeks);
  const topicsLeft = Math.max(0, topics.length - doneTopics);
  const practiceLeft = Math.max(0, practice.length - donePractice);
  const topicsPerWeek = Math.ceil(topicsLeft / remainingWeeks);
  const practicePerWeek = Math.ceil(practiceLeft / remainingWeeks);
  const dayCount = getDayCountForPace(deadline);
  const dailyTopicGoal = formatDailyTopicGoal(topicsLeft, dayCount);
  const dailyPracticeGoal = formatDailyPracticeGoal(practiceLeft, dayCount);
  const sprintWeeks = getSprintWeekStats(topics, practice, deadline);
  const currentText = deadline.isDateBased
    ? `сейчас учебная неделя ${deadline.currentSprintWeek}/${deadline.totalWeeks}, до экзамена ${deadline.daysLeft} дней`
    : "дата экзамена не задана, используется ручной режим: неделя 1/11";

  const summary = `
    <article class="week-card pace-overview goal-overview">
      <div class="week-number">${deadline.isDateBased ? escapeHTML(deadline.currentSprintWeek) : "1"}</div>
      <span class="week-status current">цель на день</span>
      <h3>${escapeHTML(dailyTopicGoal)} + ${escapeHTML(dailyPracticeGoal)} + короткое повторение</h3>
      <p><strong>Осталось пройти:</strong> ${topicsLeft}/${topics.length} тем и ${practiceLeft}/${practice.length} задач практикума.</p>
      <p><strong>Недельный ориентир:</strong> примерно ${topicsPerWeek} тем и ${practicePerWeek} задач в неделю.</p>
      <p><strong>Календарь:</strong> ${currentText}. Прошедшие недели отмечаются как «прошла», текущая — «сейчас».</p>
      <p><strong>Принцип:</strong> темы не выбрасываются; исходная карта сжата в 11 календарных недель.</p>
    </article>
  `;

  $("planList").innerHTML = summary + sprintWeeks.map((item) => `
    <article class="week-card ${item.state}-week ${item.state === "current" ? "active-week" : ""}">
      <div class="week-number">${escapeHTML(item.week)}</div>
      <span class="week-status ${escapeHTML(item.state)}">${escapeHTML(getWeekStateLabel(item.state))}</span>
      <h3>${escapeHTML(item.focus)}</h3>
      <p><strong>Сжато из:</strong> ${escapeHTML(item.sections)}</p>
      <p><strong>Должно быть готово:</strong> ${escapeHTML(item.ready || "Повторение и добивание слабых мест")}</p>
      <p><strong>Проверка:</strong> ${escapeHTML(item.check || "Проверить понимание и решить практику")}</p>
      <p><strong>Прогресс недели:</strong> ${item.done}/${item.total} тем · ${item.practiceDone}/${item.practiceTotal} задач.</p>
    </article>
  `).join("");
}

function renderGuide() {
  const reviewGuide = [
    "Повторение считается по упрощённой интервальной схеме: чем хуже воспроизведение, тем короче интервал.",
    "Статусы «Повторить» и «Сложно» имеют приоритет и попадают в ближайшее повторение.",
    "После повторения нажимай «Повторила сегодня»: сайт обновит дату и уберёт тему из срочного повторения до следующего интервала.",
    "Для тем ключевой параметр — самооценка 0–5. Для задач учитываются статус, число попыток и последняя дата решения.",
  ];
  const items = [...reviewGuide, ...DATA.guide];
  $("guideList").innerHTML = `<ol>${items.map((item) => `<li>${escapeHTML(item)}</li>`).join("")}</ol>`;
}

function bindTopicEvents() {
  document.querySelectorAll(".topic-section[data-section]").forEach((node) => node.addEventListener("toggle", (event) => {
    rememberTopicSectionState(event.currentTarget.dataset.section, event.currentTarget.open);
  }));
  document.querySelectorAll(".topic-details[data-topic-id]").forEach((node) => node.addEventListener("toggle", (event) => {
    rememberTopicDetailsState(event.currentTarget.dataset.topicId, event.currentTarget.open);
  }));
  document.querySelectorAll(".js-topic-status").forEach((node) => node.addEventListener("change", (event) => {
    const id = event.target.dataset.id;
    const status = event.target.value;
    const current = getTopics().find((item) => item.id === id) || {};
    const patch = { status };
    if (status === "Повторить") {
      patch.repeatMarkedAt = todayISO();
      patch.repeatPending = true;
    }
    if (status !== "Повторить") {
      patch.repeatMarkedAt = "";
      patch.repeatPending = false;
    }
    if (["Готово", "Сложно"].includes(status) && !current.lastReview) patch.lastReview = todayISO();
    setItemProgress("topics", id, patch);
  }));
  document.querySelectorAll(".js-topic-score").forEach((node) => node.addEventListener("change", (event) => {
    const value = event.target.value === "" ? "" : String(Math.max(0, Math.min(5, Number(event.target.value))));
    setItemProgress("topics", event.target.dataset.id, { score: value });
  }));
  document.querySelectorAll(".js-topic-review").forEach((node) => node.addEventListener("change", (event) => {
    setItemProgress("topics", event.target.dataset.id, { lastReview: event.target.value });
  }));
  document.querySelectorAll(".js-topic-notes").forEach((node) => node.addEventListener("change", (event) => {
    setItemProgress("topics", event.target.dataset.id, { notesReady: event.target.value });
  }));
  document.querySelectorAll(".js-topic-example").forEach((node) => node.addEventListener("change", (event) => {
    setItemProgress("topics", event.target.dataset.id, { exampleReady: event.target.value });
  }));
  document.querySelectorAll(".js-topic-comment").forEach((node) => node.addEventListener("change", (event) => {
    setItemProgress("topics", event.target.dataset.id, { comment: event.target.value });
  }));
  document.querySelectorAll("[data-open-practice]").forEach((node) => node.addEventListener("click", (event) => {
    event.preventDefault();
    const topicId = event.currentTarget.dataset.openPractice;
    setActiveTab("practice");
    renderPractice(topicId);
  }));
}

function bindPracticeEvents() {
  document.querySelectorAll(".js-practice-status").forEach((node) => node.addEventListener("change", (event) => {
    const id = event.target.dataset.id;
    const status = event.target.value;
    const current = getPractice().find((item) => item.id === id) || {};
    const patch = { status };
    if (status === "Повторить") {
      patch.repeatMarkedAt = todayISO();
      patch.repeatPending = true;
    }
    if (status !== "Повторить") {
      patch.repeatMarkedAt = "";
      patch.repeatPending = false;
    }
    if (["Решено", "Сложно"].includes(status) && !current.lastDate) patch.lastDate = todayISO();
    setItemProgress("practice", id, patch);
  }));
  document.querySelectorAll(".js-practice-attempts").forEach((node) => node.addEventListener("change", (event) => {
    const value = event.target.value === "" ? "" : Math.max(0, Number(event.target.value));
    setItemProgress("practice", event.target.dataset.id, { attempts: value });
  }));
  document.querySelectorAll(".js-practice-date").forEach((node) => node.addEventListener("change", (event) => {
    setItemProgress("practice", event.target.dataset.id, { lastDate: event.target.value });
  }));
  document.querySelectorAll(".js-practice-comment").forEach((node) => node.addEventListener("change", (event) => {
    setItemProgress("practice", event.target.dataset.id, { comment: event.target.value });
  }));
}

function bindReviewEvents() {
  document.querySelectorAll(".js-review-done").forEach((node) => node.addEventListener("click", (event) => {
    const { kind, id } = event.currentTarget.dataset;
    const today = todayISO();
    if (kind === "topic") {
      const current = getTopics().find((item) => item.id === id) || {};
      setItemProgress("topics", id, {
        lastReview: today,
        repeatMarkedAt: current.status === "Повторить" ? (current.repeatMarkedAt || today) : (current.repeatMarkedAt || ""),
        repeatPending: current.status === "Повторить" ? false : (current.repeatPending || false),
      });
    } else {
      const current = getPractice().find((item) => item.id === id) || {};
      setItemProgress("practice", id, {
        lastDate: today,
        repeatMarkedAt: current.status === "Повторить" ? (current.repeatMarkedAt || today) : (current.repeatMarkedAt || ""),
        repeatPending: current.status === "Повторить" ? false : (current.repeatPending || false),
      });
    }
  }));
  document.querySelectorAll(".js-review-open-topic").forEach((node) => node.addEventListener("click", (event) => {
    const query = event.currentTarget.dataset.query;
    setActiveTab("topics");
    $("topicSearch").value = query;
    renderTopics();
  }));
}

function setActiveTab(tabName) {
  document.querySelectorAll(".tab").forEach((tab) => tab.classList.toggle("active", tab.dataset.tab === tabName));
  document.querySelectorAll(".tab-panel").forEach((panel) => panel.classList.toggle("active", panel.id === tabName));
  location.hash = tabName;
}

function renderAll() {
  renderKpis();
  renderTopics();
  renderPractice();
  renderReview();
  renderPlan();
  renderGuide();
}

function exportProgress() {
  const payload = {
    exportedAt: new Date().toISOString(),
    version: 2,
    progress,
  };
  const blob = new Blob([JSON.stringify(payload, null, 2)], { type: "application/json" });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = "exam-tracker-progress.json";
  link.click();
  URL.revokeObjectURL(url);
}

function importProgress(file) {
  const reader = new FileReader();
  reader.onload = () => {
    try {
      const payload = JSON.parse(reader.result);
      progress = payload.progress || payload;
      if (!progress.topics) progress.topics = {};
      if (!progress.practice) progress.practice = {};
      if (!progress.settings) progress.settings = {};
      saveProgress();
      renderAll();
      alert("Прогресс импортирован.");
    } catch {
      alert("Не удалось импортировать файл. Нужен JSON, экспортированный из этого трекера.");
    }
  };
  reader.readAsText(file);
}

function initEvents() {
  document.querySelectorAll(".tab").forEach((tab) => {
    tab.addEventListener("click", () => setActiveTab(tab.dataset.tab));
  });

  ["topicSearch", "sectionFilter", "levelFilter", "statusFilter"].forEach((id) => $(id).addEventListener("input", renderTopics));
  ["practiceSearch", "difficultyFilter", "practiceStatusFilter", "practiceMacroFilter"].forEach((id) => $(id).addEventListener("input", () => renderPractice()));
  ["reviewSearch", "reviewKindFilter", "reviewRangeFilter", "reviewReasonFilter"].forEach((id) => $(id).addEventListener("input", renderReview));

  $("exportProgressBtn").addEventListener("click", exportProgress);
  $("importProgressInput").addEventListener("change", (event) => {
    const file = event.target.files?.[0];
    if (file) importProgress(file);
    event.target.value = "";
  });

  $("resetProgressBtn").addEventListener("click", () => {
    if (confirm("Сбросить весь сохранённый прогресс и дату экзамена в этом браузере?")) {
      progress = { topics: {}, practice: {}, settings: {} };
      saveProgress();
      renderAll();
    }
  });
}

initEvents();
renderAll();

const hash = location.hash.replace("#", "");
if (["topics", "practice", "review", "plan", "guide"].includes(hash)) {
  setActiveTab(hash);
}
